// ============================================
// HLJ DEV — Kiwify Payload Normalizer v1.0
// ============================================
// Normaliza o payload bruto da Kiwify para
// o schema de 'vendas' do Supabase.
// Ref: Kiwify Webhook Docs (eventos: order_approved,
//      order_refunded, order_chargeback)
// ============================================

const body = $input.first().json.body;

// Map de IDs de produto Kiwify para nomes legíveis
const PRODUTOS = {
  'KIWIFY_PRODUCT_PROMPTS': 'Mega Pack de Prompts Elite',
  'KIWIFY_PRODUCT_MASTERCLASS': 'I.A. Masterclass Pro',
  'KIWIFY_PRODUCT_BUNDLE': 'Acesso Premium Total'
};

// Normaliza status do evento Kiwify
const STATUS_MAP = {
  'order_approved': 'aprovado',
  'order_refunded': 'reembolsado',
  'order_chargeback': 'chargeback',
  'order_rejected': 'rejeitado',
  'order_waiting_payment': 'aguardando'
};

const status = STATUS_MAP[body.type] || body.type;
const produtoId = body.product?.id || body.Product?.id || 'DESCONHECIDO';
const produtoNome = PRODUTOS[produtoId] || body.product?.name || produtoId;

const venda = {
  kiwify_order_id: body.order?.id || body.id,
  kiwify_event: body.type,
  produto: produtoNome,
  produto_id: produtoId,
  cliente_nome: body.Customer?.name || body.customer?.name,
  cliente_email: body.Customer?.email || body.customer?.email,
  cliente_whatsapp: body.Customer?.mobile || body.customer?.mobile || null,
  valor: parseFloat(body.order?.amount || body.amount || '0') / 100, // Kiwify envia em centavos
  status: status,
  metodo_pagamento: body.payment?.method || body.Payment?.method || 'unknown',
  afiliado: body.Commissions?.AffiliateName || null,
  created_at: new Date().toISOString()
};

return [{ json: venda }];

// Mensagem de boas-vindas personalizada por produto
const venda = $('Normalizar Payload Kiwify').first().json;

const BOAS_VINDAS = {
  'Mega Pack de Prompts Elite': `🚀 *Bem-vindo ao Pack Elite!*

Oi ${venda.cliente_nome?.split(' ')[0]}! Seu acesso ao *Mega Pack de Prompts* foi liberado!

📦 Acesse seu material aqui: [LINK_DO_PACK]

Qualquer dúvida, é só responder nesta mensagem. Bons prompts! ⚡`,
  'I.A. Masterclass Pro': `🧠 *Seu Acesso à Masterclass foi Liberado!*

Oi ${venda.cliente_nome?.split(' ')[0]}! Seja bem-vindo à *I.A. Masterclass Pro*!

🎓 Acesse sua área de alunos: [LINK_DA_MASTERCLASS]

O módulo 1 já está te esperando. Qualquer dúvida, responda aqui! 💪`,
  'Acesso Premium Total': `🏆 *Acesso Premium Total Liberado!*

Oi ${venda.cliente_nome?.split(' ')[0]}! Você fez a escolha certa!

📦 Pack de Prompts: [LINK_DO_PACK]
🎓 Masterclass: [LINK_DA_MASTERCLASS]
📋 Materiais Extras: [LINK_EXTRAS]

Você tem suporte prioritário. Responda aqui para qualquer dúvida! 🔝`
};

const mensagem = BOAS_VINDAS[venda.produto] || `✅ Compra confirmada! Oi ${venda.cliente_nome}, obrigado pela sua compra de ${venda.produto}. Responda aqui para receber seu acesso.`;

// Formata número para WhatsApp
const numero = venda.cliente_whatsapp
  ? '55' + venda.cliente_whatsapp.replace(/\D/g, '')
  : null;

return [{ json: { mensagem, numero, venda } }];

